// Default test payload for manual execution
return [{
  json: {
    body: {
      title: 'Deep Focus Flow',
      category: 'Focus',
      mood: 'calm, rhythmic, ambient, concentration',
      duration_seconds: 30
    }
  }
}];

const input = $input.first().json.body || $input.first().json;

const title = input.title || 'Calm Focus';
const category = input.category || 'Focus';
const mood = input.mood || 'calm, meditative, ambient';
const duration_seconds = input.duration_seconds || 120;

const musicPrompt = `${mood} instrumental track for ${category.toLowerCase()}. Ambient meditation music with soft pads, gentle drones, binaural-inspired stereo panning. No vocals. Title: ${title}.`;

const imagePrompt = `Abstract digital artwork for a meditation audio track called "${title}". Theme: ${category}. Style: cosmic gradients, deep blues and purples, soft glowing orbs, sound wave visualizations, sacred geometry, aurora lights, dark background, premium minimalist design, no text.`;

return [{
  json: {
    title,
    category,
    mood,
    duration_seconds,
    musicPrompt,
    imagePrompt,
    timestamp: new Date().toISOString()
  }
}];

const audioItem = $input.first();
const promptData = $('Prepare Prompts').first().json;

const hasBinary = audioItem.binary && audioItem.binary.audioData;

return [{
  json: {
    audioGenerated: !!hasBinary,
    title: promptData.title,
    category: promptData.category,
    mood: promptData.mood,
    duration_seconds: promptData.duration_seconds,
    imagePrompt: promptData.imagePrompt,
    musicPrompt: promptData.musicPrompt,
    mimeType: hasBinary ? audioItem.binary.audioData.mimeType : null,
    fileSize: hasBinary ? audioItem.binary.audioData.fileSize : null,
    fileName: hasBinary ? audioItem.binary.audioData.fileName : null
  },
  binary: audioItem.binary || {}
}];

const input = $input.first();
const audioNode = $('Process Audio Result').first();

const hasImage = input.binary && input.binary.imageData;

const result = {
  success: true,
  track: {
    title: audioNode.json.title,
    category: audioNode.json.category,
    mood: audioNode.json.mood,
    duration_seconds: audioNode.json.duration_seconds,
    audioMimeType: audioNode.json.mimeType,
    audioFileSize: audioNode.json.fileSize
  },
  coverArt: {
    generated: !!hasImage,
    mimeType: hasImage ? input.binary.imageData.mimeType : null
  },
  prompts: {
    music: audioNode.json.musicPrompt,
    image: audioNode.json.imagePrompt
  },
  generatedAt: new Date().toISOString()
};

// Merge binary data from both nodes
const binary = {};
if (audioNode.binary && audioNode.binary.audioData) {
  binary.audioData = audioNode.binary.audioData;
}
if (hasImage) {
  binary.imageData = input.binary.imageData;
}

return [{ json: result, binary }];
